import retriever  # hypothetical retrieval client

AVAILABLE_CORPORA = {"default", "legal", "medical"}

def search_docs(query: str, top_k: int = 5, corpus: str = "default") -> list[str]:
    """Return the top-k document IDs matching query from corpus."""    if not query.strip():
        raise ValueError("query must not be empty")
    if top_k < 1:
        raise ValueError(f"top_k must be >= 1, got {top_k}")
    if corpus not in AVAILABLE_CORPORA:
        raise RuntimeError(f"corpus {corpus!r} not available")

    hits = retriever.search(query, corpus=corpus)
    return [h.doc_id for h in hits[:top_k]]

