import inspect
from typing import get_type_hints

def signature_to_schema(fn) -> dict:
    """Generate a minimal JSON schema dict from a function's annotations."""    hints = get_type_hints(fn)
    hints.pop("return", None)
    sig = inspect.signature(fn)
    props = {}
    required = []
    for name, param in sig.parameters.items():
        if name == "self":
            continue
        py_type = hints.get(name, str)
        json_type = {int: "integer", float: "number",
                     bool: "boolean", str: "string"}.get(py_type, "string")
        props[name] = {"type": json_type}
        if param.default is inspect.Parameter.empty:
            required.append(name)
    return {"type": "object", "properties": props, "required": required}

