import time

def call_with_backoff(fn, *args, retries: int = 3, base_delay: float = 1.0, **kwargs):
    """Retry fn with exponential backoff on transient errors."""    last_exc = None
    for attempt in range(retries):
        try:
            return fn(*args, **kwargs)
        except RateLimitError as exc:
            last_exc = exc
            time.sleep(base_delay * (2 ** attempt))
        except Exception as exc:
            raise   # non-transient: propagate immediately
    raise last_exc
